import { NextResponse } from 'next/server'
import type { NextRequest } from 'next/server'

const PUBLIC_PATHS = new Set([
  '/login',
  '/signup',
  '/forgot-password',
  '/api/auth/login',
  '/api/auth/signup',
])

const isPublic = (pathname: string) => {
  if (
    pathname.startsWith('/_next') ||
    pathname.startsWith('/static') ||
    pathname === '/favicon.ico'
  ) {
    return true
  }
  for (const p of PUBLIC_PATHS) if (pathname.startsWith(p)) return true
  return false
}

const verifyToken = (token?: string): boolean => {
  // TODO: Replace with real verification (e.g. JWT, session check, etc.)
  return typeof token === 'string' && token.length > 10
}

const redirectToLogin = (req: NextRequest) => {
  const url = req.nextUrl.clone()
  url.pathname = '/login'
  url.searchParams.set('redirect', req.nextUrl.pathname + req.nextUrl.search)
  return NextResponse.redirect(url)
}

export function middleware(req: NextRequest) {
  const { pathname } = req.nextUrl

  if (isPublic(pathname)) {
    return NextResponse.next()
  }

  const token =
    req.cookies.get('auth_token')?.value ?? req.cookies.get('token')?.value

  if (!verifyToken(token)) {
    return redirectToLogin(req)
  }

  const requestHeaders = new Headers(req.headers)
  requestHeaders.set('x-user-authenticated', 'true')

  return NextResponse.next({
    request: {
      headers: requestHeaders,
    },
  })
}

export const config = {
  matcher: '/((?!_next/static|_next/image|favicon.ico).*)',
}